import { test, expect } from '@playwright/test'

const STATES = ['default', 'hover', 'focus'] as const

test.describe.configure({ mode: 'parallel' })
test.describe('BooksToscrape — interaction-state visual @ https://books.toscrape.com/catalogue/category/books/travel_2/index.html', () => {
  test('@kind:visual-state @smoke primary CTA across states', async ({ page }) => {
    await page.goto('/catalogue/category/books/travel_2/index.html')
    await page.waitForLoadState('networkidle').catch(() => {})
    const target = page.getByRole('link').first()
    if (await target.count() === 0) {
      test.skip(true, 'no primary CTA detected on this page')
      return
    }

    for (const state of STATES) {
      switch (state) {
        case 'hover':
          await target.hover().catch(() => {})
          break
        case 'focus':
          await target.focus().catch(() => {})
          break
        default:
          // default state — no interaction
          break
      }
      await expect(target).toHaveScreenshot(`bookstoscrape-cta-${state}.png`, {
        maxDiffPixelRatio: 0.02,
        animations: 'disabled',
      })
    }
  })
})

